import sys,requests
from requests.exceptions import RequestException
base='http://localhost:80/'
paths=['admin','admin/','login','register','signup','api','api/','api/v1','dashboard','uploads','static','assets','server-status','status','health','metrics','actuator','console','debug','test','old','backup.zip','backup.tar.gz','db.sqlite3','.env','.htaccess','phpinfo.php','info.php','index.php','wordpress','wp-admin','wp-login.php','robots.txt','sitemap.xml','.git/HEAD','.svn/entries','.DS_Store','cgi-bin/','cgi-bin/test.cgi','cgi-bin/index.cgi','icons/','secret','private','config','config.php']

s=requests.Session()
for p in paths:
    url=base+p
    try:
        r=s.get(url, timeout=5, allow_redirects=False)
        print(r.status_code, p, 'len=', len(r.content))
        if 'Server' in r.headers:
            print('Server:', r.headers['Server'])
        if 'X-Powered-By' in r.headers:
            print('X-Powered-By:', r.headers['X-Powered-By'])
    except RequestException as e:
        print('ERR', p, e)

